hl.window_rule({
  match = {
    class = "^(Emulator)$",
  },
  float = true,
  border_size = 0,
})

hl.window_rule({
  match = {
    title = "^(Open .*)$",
  },
  float = true,
})

hl.window_rule({
  match = {
    title = "^(Select .*Folder)",
  },
  float = true,
})

hl.window_rule({
  match = {
    title = "^(Save .*)",
  },
  float = true,
})

hl.window_rule({
  match = {
    class = "^(vesktop)$",
    title = "^(vesktop)$",
  },
  no_initial_focus = true,
})

hl.window_rule({
  name = "flameshot-multi-display-fix",
  match = {
    class = "flameshot",
  },
  animation = "fade",
  rounding = 0,
  border_size = 0,
  fullscreen_state = "0 0",
  float = true,
  pin = true,
  monitor = "HDMI-A-2",
  move = "0 0",
  -- size = (monitor_w*3) (monitor_h)
  size = "500 500",
})

hl.window_rule({
  match = {
    class = "^(\\.?blueman-manager)",
  },
  float = true,
  pin = true,
})

hl.window_rule({
  match = {
    title = "^(Save As)$",
  },
  float = true,
})

hl.window_rule({
  match = {
    class = "^(nm-connection-editor)$",
  },
  float = true,
  pin = true,
})

hl.window_rule({
  match = {
    title = "^(Picture-in-Picture)$",
  },
  float = true,
  border_size = 0,
})

hl.window_rule({
  match = {
    title = "^(Select Executable)$",
  },
  float = true,
})

hl.window_rule({
  match = {
    class = "^(org.keepassxc.KeePassXC)$",
  },
  float = true,
